import os
import requests
import torch
import torchvision.models as models
from torchvision import transforms
from torch.utils.data import DataLoader, Dataset
import torch.optim as optim
import torch.nn as nn

class CustomDataset(Dataset):
    def __init__(self, data, labels, transform=None):
        self.data = data
        self.labels = labels
        self.transform = transform

    def __len__(self):
        return len(self.data)

    def __getitem__(self, idx):
        sample = self.data[idx]
        label = self.labels[idx]
        if self.transform:
            sample = self.transform(sample)
        return sample, label

def download_model(url, save_path):
    response = requests.get(url)
    with open(save_path, 'wb') as f:
        f.write(response.content)

def load_model(checkpoint_path, num_classes):
    model = models.resnet18(pretrained=False)
    model.fc = nn.Linear(model.fc.in_features, num_classes)
    model.load_state_dict(torch.load(checkpoint_path))
    return model

def fine_tune_model(model, dataloader, num_epochs, learning_rate):
    criterion = nn.CrossEntropyLoss()
    optimizer = optim.Adam(model.parameters(), lr=learning_rate)

    for epoch in range(num_epochs):
        model.train()
        for inputs, labels in dataloader:
            optimizer.zero_grad()
            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()

def main():
    model_url = 'https://path_to_your_model_checkpoint.pth'
    checkpoint_path = 'model_checkpoint.pth'
    download_model(model_url, checkpoint_path)

    num_classes = 10  # Change based on your dataset
    model = load_model(checkpoint_path, num_classes)

    # Example data and labels
    data = []  # Replace with your data
    labels = []  # Replace with your labels
    transform = transforms.Compose([transforms.ToTensor()])
    dataset = CustomDataset(data, labels, transform)
    dataloader = DataLoader(dataset, batch_size=32, shuffle=True)

    fine_tune_model(model, dataloader, num_epochs=5, learning_rate=0.001)

if __name__ == '__main__':
    main()